#include <stdio.h>
int main(void) {
    int n = 42;
    float f = 3.14159f;
    char *s = "KernelForge";
    unsigned int h = 0xDEAD;
    printf("Int     : %d\n", n);
    printf("Float   : %.2f\n", f);
    printf("String  : %s\n", s);
    printf("Hex     : 0x%04X\n", h);
    printf("Padded  : %08d\n", n);
    printf("Neg pad : %-10d|\n", n);
    return 0;
}

