#include <stdio.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    int n = 42;
    float f = 3.14159f;
    char *s = "KernelForge";
    unsigned int h = 0xDEAD;
    printf("Int     : %d\n", n);      // ★ %d pour entier
    printf("Float   : %.2f\n", f);   // ★ %.2f = 2 décimales
    printf("String  : %s\n", s);     // ★ %s pour char*
    printf("Hex     : 0x%04X\n", h); // ★ %04X = hex 4 chiffres majuscule
    printf("Padded  : %08d\n", n);   // ★ %08d = 8 chiffres, 0-fill
    printf("Neg pad : %-10d|\n", n); // ★ %-10d = aligné à gauche
    return 0;
}

